SELECT COUNT(*) 
FROM embarkation 
WHERE embarkation_port = 'S';

SELECT passenger_id, embarkation_port
FROM embarkation
WHERE embarkation_port = 'S';

SELECT AVG(total_fare) AS average_total_fare
FROM (
    SELECT passenger_id, SUM(fare) AS total_fare
    FROM tickets
    GROUP BY passenger_id
) AS total_fares;
